use std::time::Instant;

pub async fn index() -> impl IntoResponse {
    let pool = rullst::db::Orm::pool();
    
    // Get all monitors
    let monitors = Monitor::all().await.unwrap_or_default();
    
    // Use a Window Function to fetch the last 20 heartbeats for ALL monitors in a single query (solves N+1)
    let history_flat: Vec<Heartbeat> = rullst::db::sqlx::query_as(
        "SELECT id, monitor_id, status_code, response_time_ms, is_up, error_message 
         FROM (
             SELECT *, ROW_NUMBER() OVER(PARTITION BY monitor_id ORDER BY id DESC) as rn 
             FROM heartbeats
         ) WHERE rn <= 20"
    )
    .fetch_all(pool)
    .await
    .unwrap_or_default();

    // Package monitors with their heartbeats
    let mut monitors_with_history = Vec::new();
    for monitor in monitors {
        let mut history: Vec<Heartbeat> = history_flat
            .iter()
            .filter(|h| h.monitor_id == monitor.id)
            .cloned()
            .collect();
        
        // Reverse so chronological order is left-to-right
        history.reverse();
        
        monitors_with_history.push((monitor, history));
    }

    Html(uptime::dashboard_page(monitors_with_history))
}

#[derive(Deserialize)]
pub struct CreateMonitorPayload {
    pub name: String,
    pub url: String,
}

pub async fn store_monitor(Form(payload): Form<CreateMonitorPayload>) -> impl IntoResponse {
    let mut monitor = Monitor {
        id: 0,
        name: payload.name,
        url: payload.url,
        is_active: 1,
    };
    let _ = monitor.save().await;

    Redirect::to("/")
}

pub async fn toggle_monitor(Path(id): Path<i32>) -> impl IntoResponse {
    if let Ok(mut monitor) = Monitor::find(id).await {
        monitor.is_active = if monitor.is_active == 1 { 0 } else { 1 };
        let _ = monitor.save().await;
    }

    Redirect::to("/")
}

// Background Ping Job execution
pub async fn ping_monitors() -> Result<(), Box<dyn std::error::Error>> {
    let pool = rullst::db::Orm::pool();
    
    // Get active monitors
    let active_monitors: Vec<Monitor> = Monitor::all().await.unwrap_or_default().into_iter().filter(|m| m.is_active == 1).collect();

    // Create a non-reusable client to prevent session caching issues
    let client = reqwest::Client::builder()
        .timeout(std::time::Duration::from_secs(10))
        .danger_accept_invalid_certs(true)
        .build()
        .unwrap_or_default();

    let mut handles = Vec::new();

    for monitor in active_monitors {
        let client_clone = client.clone();
        
        handles.push(tokio::spawn(async move {
            let start = Instant::now();
            let res = client_clone.get(&monitor.url).send().await;
            let duration = start.elapsed().as_millis() as i32;

            let (status_code, is_up, error_msg) = match res {
                Ok(response) => {
                    let code = response.status().as_u16() as i32;
                    let up = if code >= 200 && code < 400 { 1 } else { 0 };
                    (code, up, "".to_string())
                }
                Err(e) => {
                    (0, 0, e.to_string())
                }
            };

            // Write heartbeat log
            let mut heartbeat = Heartbeat {
                id: 0,
                monitor_id: monitor.id,
                status_code,
                response_time_ms: duration,
                is_up,
                error_message: if error_msg.is_empty() { None } else { Some(error_msg) },
            };
            let _ = heartbeat.save().await;

            println!("📡 Checked '{}' ({}): {} | {}ms", monitor.name, monitor.url, status_code, duration);
        }));
    }

    // Wait for all checks to complete
    for handle in handles {
        let _ = handle.await;
    }

    Ok(())
}
